sql:
SELECT request_id, COUNT(*) AS Appeal_Count
FROM appeals
GROUP BY request_id;

SELECT COUNT(*)
FROM foia_requests
WHERE submit_date > '2020-01-01';

SELECT requester_id 
FROM requesters 
WHERE full_name = 'Jane Doe';

external_knowledge:
- 'forest': represents the overall system of FOIA requests;
- 'explorer': refers to the requester;
- 'landmarks': symbolizes the specific elements of each FOIA request, such as numbers and identifiers;
- 'guardians of the knowledge': corresponds to the offices handling the requests;
- 'challenges faced': includes any exemptions applied and appeals made;
- 'journey's start and end times': involves the processing times;
- 'price paid for enlightenment': refers to the payment amounts made for processing the requests;
- 'ongoing quest': indicates requests that are still open;
- 'who have reached their destination': signifies requests that are closed.

sql:
SELECT IFNULL(SUM(amount), 0) AS total_amount_paid
FROM payment_records
WHERE strftime('%Y-%m', payment_date) = '2013-08';

SELECT foia_requests.request_id, foia_requests.request_number, request_statuses.status_name
FROM foia_requests
INNER JOIN request_statuses ON foia_requests.status_id = request_statuses.status_id;

SELECT payment_id, amount, payment_date, payment_method
FROM payment_records
WHERE request_id = (SELECT request_id FROM foia_requests WHERE request_number = 'FOIA-001');

SELECT request_id, status_id
FROM foia_requests
ORDER BY submit_date DESC;

SELECT requester_id
FROM foia_requests
WHERE request_number = 'FOIA-2013-05024';

SELECT AVG(pt.duration) AS Average_Appeal_Processing_Time
FROM processing_times AS pt
JOIN appeals AS a ON pt.request_id = a.request_id;
